.badge-pass { display:inline-block; padding:5px 14px; border-radius:20px; font-weight:700; font-size:.9rem; background:var(--pass-bg); color:var(--pass); }
.badge-fail { display:inline-block; padding:5px 14px; border-radius:20px; font-weight:700; font-size:.9rem; background:var(--fail-bg); color:var(--fail); }

/* в”Җв”Җ Summary check rows в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
.chk-row { display:flex; justify-content:space-between; align-items:center; padding:5px 0; border-bottom:1px dashed #e8edf4; font-size:.85rem; }
.chk-row:last-child { border:none; }
.ratio-bar { height:7px; background:#e8edf4; border-radius:4px; overflow:hidden; margin-top:3px; }
.ratio-fill { height:100%; border-radius:4px; transition:width .5s; }
.fill-pass { background:var(--pass); }
.fill-warn { background:var(--warn); }
.fill-fail { background:var(--fail); }

/* в”Җв”Җ Formula step cards в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
.step-card { margin-bottom:14px; }
.step-title {
  background:var(--blue); color:#fff; padding:8px 14px;
  border-radius:8px 8px 0 0; font-size:.88rem; font-weight:700;
}
.step-subtitle {
  background:#e8f0f8; color:var(--blue); padding:5px 14px;
  font-size:.78rem; font-style:italic;
}
.step-body { background:#fff; border:1px solid #dde3ec; border-top:none; border-radius:0 0 8px 8px; overflow:hidden; }

/* Formula table */
.ftable { width:100%; border-collapse:collapse; font-size:.82rem; }
.ftable thead tr { background:#f4f7fb; }
.ftable th { padding:6px 10px; font-weight:700; color:#445; border-bottom:1px solid #dde3ec; }
.ftable td { padding:5px 10px; border-bottom:1px solid #f0f4f8; vertical-align:top; }
.ftable tr:last-child td { border-bottom:none; }
.ftable tr.check-pass { background:#f0fdf6; }
.ftable tr.check-fail { background:#fef2f2; }
.sym { font-family:'Fira Mono',monospace; font-weight:600; color:var(--blue); white-space:nowrap; }
.formula-txt { font-family:'Fira Mono',monospace; color:#555; }
.sub-txt { font-family:'Fira Mono',monospace; color:#777; font-size:.78rem; }
.val-txt { font-family:'Fira Mono',monospace; font-weight:700; color:#1a1a2e; text-align:right; }
.val-pass { color:var(--pass); }
.val-fail { color:var(--fail); }
.unit-txt { color:#888; font-size:.75rem; }
.check-icon { font-size:1rem; }

/* Load case table */
.lc-table { width:100%; border-collapse:collapse; font-size:.78rem; }
.lc-table th { background:#f4f7fb; padding:5px 8px; font-weight:700; border-bottom:1px solid #dde3ec; }
.lc-table td { padding:4px 8px; border-bottom:1px solid #f0f4f8; }
.lc-table tr.crit { background:#fff8e8; font-weight:700; }
.lc-table tr.fail { background:#fef2f2; }

/* Full report */
pre.rpt { background:#1a1a2e; color:#a8d8ea; border-radius:8px; padding:14px; font-size:.74rem; line-height:1.65; white-space:pre-wrap; word-break:break-word; max-height:420px; overflow-y:auto; font-family:'Fira Mono',monospace; }
.collapsible { cursor:pointer; user-select:none; }
.collapsible::after { content:' в–ј'; font-size:.7rem; }
.collapsible.open::after { content:' в–І'; }

/* Placeholder */
.placeholder { text-align:center; color:#aaa; padding:60px 20px; }
.placeholder svg { opacity:.2; margin-bottom:10px; }

