   Calculate
в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
async function calculate(mod) {
  const btn = document.getElementById('btn-'+mod);
  btn.innerHTML = '<span class="spinner"></span>аёҒаёіаёҘаёұаёҮаё„аёіаёҷаё§аё“...';
  btn.disabled = true;
  try {
    const res  = await fetch(API, { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({module:mod, inputs:collectInputs(mod)}) });
    const data = await res.json();
    if (data.error) showError(data.error);
    else { _lastModule=mod; _lastData=data; renderResults(mod,data); }
  } catch(e) {
    showError('а№ҖаёҠаё·а№ҲаёӯаёЎаё•а№Ҳаёӯ API а№„аёЎа№Ҳа№„аё”а№ү: '+e.message);
  } finally {
    btn.innerHTML = 'аё„аёіаёҷаё§аё“ (Calculate)';
    btn.disabled = false;
