function renderResults(mod, data) {
  document.getElementById('placeholder').style.display = 'none';
  document.getElementById('btn-pdf').style.display = '';

  const tabNames = {purlin:'а№Ғаёӣ (Purlin)',beam:'аё„аёІаёҷ (Beam)',column:'а№ҖаёӘаёІ (Column)',connection:'аёЈаёӯаёўаё•а№Ҳаёӯ (Connection)',baseplate:'а№Ғаёңа№ҲаёҷаёҗаёІаёҷ (Base Plate)'};
  document.getElementById('panel-title').textContent = 'аёңаёҘаёҒаёІаёЈаёӯаёӯаёҒа№Ғаёҡаёҡ'+tabNames[mod];
  const printTitle = {purlin:'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“аёӯаёӯаёҒа№Ғаёҡаёҡа№Ғаёӣ',beam:'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“аёӯаёӯаёҒа№Ғаёҡаёҡаё„аёІаёҷ',column:'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“аёӯаёӯаёҒа№Ғаёҡаёҡа№ҖаёӘаёІ',connection:'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“аёӯаёӯаёҒа№ҒаёҡаёҡаёЈаёӯаёўаё•а№Ҳаёӯ',baseplate:'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“аёӯаёӯаёҒа№Ғаёҡаёҡа№Ғаёңа№ҲаёҷаёҗаёІаёҷ'};
  document.getElementById('print-title').textContent = printTitle[mod] || 'аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“';
  document.getElementById('print-meta').textContent = `аё§аёұаёҷаё—аёөа№Ҳ: ${new Date().toLocaleDateString('th-TH')}  |  аё§аёӘаё—. 011038-22  |  ASD Method`;

  let html = '';
  // Summary card
  const badge = data.is_ok
    ? '<span class="badge-pass">вң“ аёңа№ҲаёІаёҷ (ADEQUATE)</span>'
    : '<span class="badge-fail">вң— а№„аёЎа№Ҳаёңа№ҲаёІаёҷ (INADEQUATE)</span>';

  if (mod==='purlin')    html = summaryPurlin(data,badge);
  else if (mod==='beam') html = summaryBeam(data,badge);
  else if (mod==='column') html = summaryColumn(data,badge);
  else html = `<div class="rcard">${badge}${data.status?`<p style="margin-top:8px;font-size:.85rem">${esc(data.status)}</p>`:''}</div>`;

  // Formula steps

