/* в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   Export PDF вҖ” calls /api/export-pdf (Python report_generator) then falls
   back to browser print if API is unavailable.
в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
async function exportPDF() {
  if (!_lastModule || !_lastData) { alert('аёҒаёЈаёёаё“аёІаё„аёіаёҷаё§аё“аёҒа№Ҳаёӯаёҷ'); return; }

  // Collect project info via modal
  const projInfo = await _promptProjectInfo();
  if (!projInfo) return;

  const btn = document.getElementById('btn-pdf');
  const origHTML = btn.innerHTML;
  btn.innerHTML = '<span class="spinner"></span>аёҒаёіаёҘаёұаёҮаёӘаёЈа№үаёІаёҮ PDF...';
  btn.disabled = true;

  try {
    const res = await fetch('/api/export-pdf', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        module:   _lastModule,
        data:     _lastData,
        project:  projInfo,
      }),
    });

    if (res.ok && res.headers.get('content-type') === 'application/pdf') {
      const blob = await res.blob();
      const url  = URL.createObjectURL(blob);
      const a    = document.createElement('a');
      a.href     = url;
      a.download = `аёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“_${_lastModule}_${new Date().toISOString().slice(0,10)}.pdf`;
      a.click();
      URL.revokeObjectURL(url);
    } else {
      // API not available вҖ” fallback to browser print
      document.querySelectorAll('#rpt-body').forEach(el => el.style.display = '');
      document.querySelectorAll('.collapsible').forEach(el => el.classList.add('open'));
      window.print();
    }
  } catch (e) {
    // Network error вҖ” fallback to browser print
    document.querySelectorAll('#rpt-body').forEach(el => el.style.display = '');
    document.querySelectorAll('.collapsible').forEach(el => el.classList.add('open'));
    window.print();
  } finally {
    btn.innerHTML = origHTML;
    btn.disabled  = false;
  }
}

function _promptProjectInfo() {
  return new Promise(resolve => {
    // Build modal
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center';

    const box = document.createElement('div');
    box.style.cssText = 'background:#fff;border-radius:10px;padding:28px 32px;width:420px;box-shadow:0 8px 32px rgba(0,0,0,.25)';

    const fields = [
      { key:'project_name', label:'аёҠаё·а№Ҳаёӯа№Ӯаё„аёЈаёҮаёҒаёІаёЈ', def:'' },
      { key:'project_no',   label:'а№ҖаёҘаёӮаё—аёөа№Ҳа№Ӯаё„аёЈаёҮаёҒаёІаёЈ', def:'' },
      { key:'client',       label:'а№ҖаёҲа№үаёІаёӮаёӯаёҮа№Ӯаё„аёЈаёҮаёҒаёІаёЈ', def:'' },
      { key:'engineer',     label:'аёӯаёӯаёҒа№Ғаёҡаёҡа№Ӯаё”аёў', def:'' },
      { key:'checker',      label:'аё•аёЈаё§аёҲаёӘаёӯаёҡа№Ӯаё”аёў', def:'' },
    ];

    let html = `<h3 style="margin:0 0 16px;color:#1b4f72;font-size:1rem">аёӮа№үаёӯаёЎаё№аёҘа№Ӯаё„аёЈаёҮаёҒаёІаёЈаёӘаёіаё«аёЈаёұаёҡаёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“</h3>`;
    fields.forEach(f => {
      html += `<div style="margin-bottom:8px">
        <label style="font-size:.82rem;display:block;margin-bottom:2px;color:#445">${f.label}</label>
        <input id="pi_${f.key}" type="text" value="${f.def}"
          style="width:100%;padding:6px 9px;border:1px solid #c8d0da;border-radius:5px;font-size:.85rem;font-family:inherit">
      </div>`;
    });
    html += `<div style="display:flex;gap:10px;margin-top:16px;justify-content:flex-end">
      <button id="pi_cancel" style="padding:7px 18px;border:1.5px solid #1b4f72;border-radius:6px;background:#fff;color:#1b4f72;cursor:pointer;font-family:inherit">аёўаёҒа№ҖаёҘаёҙаёҒ</button>
      <button id="pi_ok"     style="padding:7px 18px;border:none;border-radius:6px;background:#1b4f72;color:#fff;cursor:pointer;font-weight:700;font-family:inherit">
        <span class="material-symbols-outlined" style="font-size:14px;vertical-align:middle">picture_as_pdf</span> аёӘаёЈа№үаёІаёҮ PDF
      </button>
    </div>`;
    box.innerHTML = html;
    overlay.appendChild(box);
    document.body.appendChild(overlay);

    document.getElementById('pi_ok').onclick = () => {
      const info = {};
      fields.forEach(f => { info[f.key] = document.getElementById('pi_'+f.key).value.trim(); });
      overlay.remove();
      resolve(info);
    };
    document.getElementById('pi_cancel').onclick = () => { overlay.remove(); resolve(null); };
  });
}

