      { key:'engineer',     label:'аёӯаёӯаёҒа№Ғаёҡаёҡа№Ӯаё”аёў', def:'' },
      { key:'checker',      label:'аё•аёЈаё§аёҲаёӘаёӯаёҡа№Ӯаё”аёў', def:'' },
    ];

    let html = `<h3 style="margin:0 0 16px;color:#1b4f72;font-size:1rem">аёӮа№үаёӯаёЎаё№аёҘа№Ӯаё„аёЈаёҮаёҒаёІаёЈаёӘаёіаё«аёЈаёұаёҡаёЈаёІаёўаёҒаёІаёЈаё„аёіаёҷаё§аё“</h3>`;
    fields.forEach(f => {
      html += `<div style="margin-bottom:8px">
        <label style="font-size:.82rem;display:block;margin-bottom:2px;color:#445">${f.label}</label>
        <input id="pi_${f.key}" type="text" value="${f.def}"
          style="width:100%;padding:6px 9px;border:1px solid #c8d0da;border-radius:5px;font-size:.85rem;font-family:inherit">
      </div>`;
    });
    html += `<div style="display:flex;gap:10px;margin-top:16px;justify-content:flex-end">
      <button id="pi_cancel" style="padding:7px 18px;border:1.5px solid #1b4f72;border-radius:6px;background:#fff;color:#1b4f72;cursor:pointer;font-family:inherit">аёўаёҒа№ҖаёҘаёҙаёҒ</button>
      <button id="pi_ok"     style="padding:7px 18px;border:none;border-radius:6px;background:#1b4f72;color:#fff;cursor:pointer;font-weight:700;font-family:inherit">
        <span class="material-symbols-outlined" style="font-size:14px;vertical-align:middle">picture_as_pdf</span> аёӘаёЈа№үаёІаёҮ PDF
      </button>
    </div>`;
    box.innerHTML = html;
    overlay.appendChild(box);
    document.body.appendChild(overlay);

    document.getElementById('pi_ok').onclick = () => {
      const info = {};
      fields.forEach(f => { info[f.key] = document.getElementById('pi_'+f.key).value.trim(); });
      overlay.remove();
      resolve(info);
    };
    document.getElementById('pi_cancel').onclick = () => { overlay.remove(); resolve(null); };
  });
}

